// // This module is designed to decrement its value by one on each positive clock edge when enabled. The counter resets to zero when the reset signal is asserted.
module top_module(
out     ,  
enable  ,  
clk     ,  
reset      
);output [7:0] out;

     input enable, clk, reset;

    reg [7:0] out;

always @(posedge clk)
if (reset) begin
  out <= 8'b0 ;
end else if (enable) begin
  out <= out + 1;
end


endmodule
